<?php $s=$student??null;$person=$s->person??null;$guardians=array_map(fn($x)=>(int)$x->id,$s->guardians??[]);$primary=0;foreach($s->guardians??[] as $g)if($g->is_primary)$primary=(int)$g->id;echo form_open(get_uri('grupo_donato/school/students/save'),['id'=>'student-form','class'=>'general-form','role'=>'form']); ?>
